esqlQuery.esql:
// Per-workspace daily cost spike alert.
// Amount is in cents — 2000 = $20.00 per workspace per day.
// Adjust the threshold in the final WHERE clause.
FROM metrics-anthropic_metrics.cost-*
| WHERE anthropic.cost.amount IS NOT NULL AND anthropic.cost.workspace_id IS NOT NULL
| STATS ws_cost_cents = SUM(anthropic.cost.amount) BY anthropic.cost.workspace_id
| EVAL ws_cost_usd = ROUND(ws_cost_cents / 100.0, 2)
| WHERE ws_cost_cents > 2000
